use std::io::{self, Write};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let manifest = terax_lib::modules::capabilities::core_capability_manifest();
    let json = serde_json::to_string_pretty(&manifest)?;
    let mut stdout = io::BufWriter::new(io::stdout().lock());
    writeln!(
        stdout,
        "// @generated by `cargo run --bin export_pi_capability_manifest`\nexport const FALLBACK_CAPABILITY_MANIFEST = Object.freeze({json});"
    )?;
    Ok(())
}
